27	  async assessListingCreation(
28	    vendorId: string,
29	    breed: string,
30	    deviceFingerprint?: string,
31	    ip?: string,
32	  ): Promise<RiskFlag[]> {
33	    const flags: RiskFlag[] = [];
34	
35	    if (deviceFingerprint) {
36	      const multiAccountFlag = await this.checkMultiAccountDevice(
37	        vendorId,
38	        deviceFingerprint,
39	      );
40	      if (multiAccountFlag) flags.push(multiAccountFlag);
41	    }
42	
43	    if (ip) {
44	      const ipFlag = await this.checkIpRisk(ip);
45	      if (ipFlag) flags.push(ipFlag);
46	    }
47	
48	    const repostFlag = await this.checkFrequentRepost(vendorId, breed);
49	    if (repostFlag) flags.push(repostFlag);
50	
51	    for (const flag of flags) {
52	      await this.auditService.log({
53	        action: 'RISK_FLAG',
54	        actorId: vendorId,
55	        entityType: 'listing',
56	        deviceFingerprint,
57	        ip,
58	        after: { flag: flag.riskFlag, detail: flag.detail } as unknown as Record<string, unknown>,
59	      });
60	      logger.warn(`Risk flag: ${flag.riskFlag} for user ${vendorId}`, {
61	        context: 'RiskService',
62	      });
63	    }
64	
65	    return flags;
66	  }
