68	  async assessConversationCreation(
69	    userId: string,
70	    deviceFingerprint?: string,
71	    ip?: string,
72	  ): Promise<RiskFlag[]> {
73	    const flags: RiskFlag[] = [];
74	
75	    if (deviceFingerprint) {
76	      const multiAccountFlag = await this.checkMultiAccountDevice(userId, deviceFingerprint);
77	      if (multiAccountFlag) flags.push(multiAccountFlag);
78	    }
79	
80	    if (ip) {
81	      const ipFlag = await this.checkIpRisk(ip);
82	      if (ipFlag) flags.push(ipFlag);
83	    }
84	
85	    for (const flag of flags) {
86	      await this.auditService.log({
87	        action: 'RISK_FLAG',
88	        actorId: userId,
89	        entityType: 'conversation',
90	        deviceFingerprint,
91	        ip,
92	        after: { flag: flag.riskFlag, detail: flag.detail } as unknown as Record<string, unknown>,
93	      });
94	    }
