126	  private async checkIpRisk(ip: string): Promise<RiskFlag | null> {
127	    const oneDayAgo = new Date(Date.now() - 24 * 60 * 60 * 1000);
128	    const recentUsers = await this.userRepo
129	      .createQueryBuilder('u')
130	      .where('u.lastIp = :ip', { ip })
131	      .andWhere('u.createdAt >= :since', { since: oneDayAgo })
132	      .getCount();
133	
134	    if (recentUsers > 5) {
135	      return {
136	        riskFlag: 'ip_risk',
137	        detail: `IP ${ip} created ${recentUsers} accounts in last 24h`,
138	      };
139	    }
140	    return null;
141	  }
142	
143	  private async checkFrequentRepost(
144	    vendorId: string,
145	    breed: string,
146	  ): Promise<RiskFlag | null> {
147	    const oneHourAgo = new Date(Date.now() - 60 * 60 * 1000);
148	    const count = await this.listingRepo
149	      .createQueryBuilder('l')
150	      .where('l.vendorId = :vendorId', { vendorId })
151	      .andWhere('LOWER(l.breed) = LOWER(:breed)', { breed })
152	      .andWhere('l.createdAt >= :since', { since: oneHourAgo })
153	      .andWhere('l.deletedAt IS NULL')
154	      .getCount();
155	
156	    if (count > 5) {
157	      return {
158	        riskFlag: 'frequent_repost',
159	        detail: `Vendor posted ${count} listings for breed "${breed}" in last hour`,
160	      };
161	    }
162	    return null;
163	  }
164	}
