72	  async search(query: SearchListingsDto): Promise<PaginatedResult<Listing>> {
73	    const page = Math.max(1, query.page ?? 1);
74	    const limit = Math.min(100, Math.max(1, query.limit ?? 20));
75	    const skip = (page - 1) * limit;
76	
77	    const correctedQ = query.q ? this.correctTypos(query.q) : undefined;
78	
79	    const qb = this.listingRepo
80	      .createQueryBuilder('l')
81	      .where('l.status = :status', { status: ListingStatus.ACTIVE })
82	      .andWhere('l.deletedAt IS NULL');
83	
84	    if (correctedQ) {
85	      qb.andWhere(
86	        '(l.title ILIKE :q OR l.description ILIKE :q OR l.breed ILIKE :q)',
87	        { q: `%${correctedQ}%` },
88	      );
89	    }
90	    if (query.breed) {
91	      qb.andWhere('LOWER(l.breed) = LOWER(:breed)', { breed: query.breed });
92	    }
93	    if (query.region) {
94	      qb.andWhere('LOWER(l.region) = LOWER(:region)', { region: query.region });
95	    }
96	    if (query.minAge !== undefined) {
97	      qb.andWhere('l.age >= :minAge', { minAge: query.minAge });
98	    }
99	    if (query.maxAge !== undefined) {
100	      qb.andWhere('l.age <= :maxAge', { maxAge: query.maxAge });
101	    }
102	    if (query.minPrice !== undefined) {
103	      qb.andWhere('l.priceUsd >= :minPrice', { minPrice: query.minPrice });
104	    }
105	    if (query.maxPrice !== undefined) {
106	      qb.andWhere('l.priceUsd <= :maxPrice', { maxPrice: query.maxPrice });
107	    }
108	    if (query.minRating !== undefined) {
109	      qb.andWhere('l.rating >= :minRating', { minRating: query.minRating });
110	    }
111	    if (query.maxRating !== undefined) {
112	      qb.andWhere('l.rating <= :maxRating', { maxRating: query.maxRating });
113	    }
114	    if (query.newArrivals) {
115	      const fourteenDaysAgo = new Date(Date.now() - 14 * 24 * 60 * 60 * 1000);
116	      qb.andWhere('l.createdAt >= :since', { since: fourteenDaysAgo });
117	    }
118	
119	    this.applySorting(qb, query.sort);
120	    qb.skip(skip).take(limit);
121	
122	    const [items, total] = await qb.getManyAndCount();
123	
124	    const result: PaginatedResult<Listing> = {
125	      items,
126	      total,
127	      page,
128	      limit,
129	      totalPages: Math.ceil(total / limit),
130	    };
131	
132	    if (total === 0) {
133	      result.fallback = await this.buildFallback(query.breed ?? correctedQ);
134	    }
135	
136	    return result;
137	  }
