157	      .andWhere('l.status = :status', { status: ListingStatus.ACTIVE })
158	      .andWhere('l.deletedAt IS NULL')
159	      .limit(5)
160	      .getRawMany();
161	
162	    const seen = new Set<string>();
163	    const results: string[] = [];
164	    for (const row of [...breeds, ...titles]) {
165	      const v = row.value as string;
166	      if (!seen.has(v.toLowerCase())) {
167	        seen.add(v.toLowerCase());
168	        results.push(v);
169	      }
170	      if (results.length >= 10) break;
171	    }
172	    return results;
173	  }
