288	  private applySorting(qb: SelectQueryBuilder<Listing>, sort?: string): void {
289	    switch (sort) {
290	      case 'price_asc':
291	        qb.orderBy('l.priceUsd', 'ASC');
292	        break;
293	      case 'price_desc':
294	        qb.orderBy('l.priceUsd', 'DESC');
295	        break;
296	      case 'rating_desc':
297	        qb.orderBy('l.rating', 'DESC');
298	        break;
299	      case 'newest':
300	      default:
301	        qb.orderBy('l.createdAt', 'DESC');
302	        break;
303	    }
304	  }
