306	  private async buildFallback(
307	    breedHint?: string,
308	  ): Promise<{ similarBreed: Listing[]; trending: Listing[] }> {
309	    let similarBreed: Listing[] = [];
310	    if (breedHint) {
311	      similarBreed = await this.listingRepo
312	        .createQueryBuilder('l')
313	        .where('l.status = :status', { status: ListingStatus.ACTIVE })
314	        .andWhere('l.deletedAt IS NULL')
315	        .andWhere('l.breed ILIKE :breed', { breed: `%${breedHint}%` })
316	        .orderBy('l.rating', 'DESC')
317	        .limit(5)
318	        .getMany();
319	    }
320	
321	    const sevenDaysAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);
322	    const trending = await this.listingRepo
323	      .createQueryBuilder('l')
324	      .where('l.status = :status', { status: ListingStatus.ACTIVE })
325	      .andWhere('l.deletedAt IS NULL')
326	      .andWhere('l.createdAt >= :since', { since: sevenDaysAgo })
327	      .orderBy('l.rating', 'DESC')
328	      .limit(5)
329	      .getMany();
330	
331	    return { similarBreed, trending };
332	  }
333	
334	  private async checkSensitiveWords(
335	    title: string,
336	    description: string,
337	  ): Promise<{ flagged: boolean; matchedWords: string[] }> {
338	    const words = await this.wordRepo.find();
339	    const combined = `${title} ${description}`.toLowerCase();
340	    const matched = words.filter((sw) => combined.includes(sw.word.toLowerCase()));
341	    return { flagged: matched.length > 0, matchedWords: matched.map((w) => w.word) };
342	  }
343	
344	  private async enforceRateLimit(vendorId: string): Promise<void> {
345	    const windowStart = new Date(Date.now() - RATE_LIMIT_WINDOW_MS);
346	    const count = await this.rateLimitRepo.count({
347	      where: {
348	        userId: vendorId,
349	        action: 'create_listing',
350	        createdAt: MoreThanOrEqual(windowStart),
351	      },
352	    });
353	    if (count >= RATE_LIMIT_MAX) {
354	      throw new HttpException('Rate limit exceeded: max 30 listings per hour', HttpStatus.TOO_MANY_REQUESTS);
355	    }
356	  }
357	
358	  private async detectDuplicate(vendorId: string, title: string): Promise<string | undefined> {
359	    const oneDayAgo = new Date(Date.now() - 24 * 60 * 60 * 1000);
360	    const recent = await this.listingRepo
361	      .createQueryBuilder('l')
362	      .where('l.vendorId = :vendorId', { vendorId })
363	      .andWhere('l.createdAt >= :since', { since: oneDayAgo })
364	      .andWhere('l.deletedAt IS NULL')
365	      .getMany();
366	
367	    const inputTokens = this.tokenize(title);
368	    if (inputTokens.length === 0) return undefined;
369	
370	    for (const listing of recent) {
371	      const existingTokens = this.tokenize(listing.title);
372	      if (existingTokens.length === 0) continue;
373	      const intersection = inputTokens.filter((t) => existingTokens.includes(t));
374	      const overlap = intersection.length / Math.max(inputTokens.length, existingTokens.length);
375	      if (overlap >= 0.8) {
376	        return `Near-duplicate detected: similar to "${listing.title}" (${Math.round(overlap * 100)}% overlap)`;
377	      }
378	    }
379	    return undefined;
380	  }
381	
382	  private tokenize(text: string): string[] {
383	    return text.toLowerCase().split(/\s+/).filter((w) => w.length > 2);
384	  }
385	}
