74	  async generateMonthly(month: string, actorId: string): Promise<Settlement[]> {
75	    const vendors = await this.userRepo.find({ where: { role: 'vendor' as any, isActive: true } });
76	    const results: Settlement[] = [];
77	
78	    for (const vendor of vendors) {
79	      const existing = await this.settlementRepo.findOne({
80	        where: { vendorId: vendor.id, month },
81	      });
82	      if (existing) continue;
83	
84	      const listings = await this.listingRepo
85	        .createQueryBuilder('l')
86	        .where('l.vendorId = :vendorId', { vendorId: vendor.id })
87	        .andWhere("to_char(l.\"createdAt\", 'YYYY-MM') = :month", { month })
88	        .getMany();
89	
90	      let totalCharges = 0;
91	      for (const listing of listings) {
92	        const freight = this.freightService.calculate({
93	          distanceMiles: 150,
94	          weightLbs: Number(listing.age) * 2 + 5,
95	          dimWeightLbs: 10,
96	          isOversized: false,
97	          isWeekend: false,
98	        });
99	        totalCharges += freight.total;
100	      }
101	
102	      const taxAmount = round(totalCharges * 0.085);
103	
104	      const settlement = this.settlementRepo.create({
105	        vendorId: vendor.id,
106	        month,
107	        totalCharges,
108	        taxAmount,
109	        status: SettlementStatus.PENDING,
110	        data: { listingCount: listings.length },
111	      });
112	      const saved = await this.settlementRepo.save(settlement);
113	      results.push(saved);
114	
115	      await this.auditService.log({
116	        action: 'settlement.generate',
117	        actorId,
118	        entityType: 'settlement',
119	        entityId: saved.id,
120	        after: { vendorId: vendor.id, month, totalCharges, taxAmount } as unknown as Record<string, unknown>,
121	      });
122	    }
123	
124	    return results;
125	  }
