128	    if (role !== 'ops_reviewer' && role !== 'admin') {
129	      throw new ForbiddenException('Only ops_reviewer can perform step 1 approval');
130	    }
131	
132	    const settlement = await this.settlementRepo.findOne({ where: { id } });
133	    if (!settlement) throw new NotFoundException('Settlement not found');
134	    if (settlement.status !== SettlementStatus.PENDING) {
135	      throw new BadRequestException('Settlement must be in pending status for step 1 approval');
136	    }
137	
138	    const before = { ...settlement } as unknown as Record<string, unknown>;
139	    settlement.status = SettlementStatus.REVIEWER_APPROVED;
140	    settlement.reviewerApprovedBy = reviewerId;
