1	import {
2	  Injectable,
3	  BadRequestException,
4	  NotFoundException,
5	  ForbiddenException,
6	} from '@nestjs/common';
7	import { InjectRepository } from '@nestjs/typeorm';
8	import { Repository, DataSource, SelectQueryBuilder } from 'typeorm';
9	import { SavedQuery } from '../database/entities/saved-query.entity';
10	import { PowerQueryDto, QueryFilterItem } from './dto/query.dto';
11	import { EncryptionService } from '../common/encryption/encryption.service';
12	
13	const ENTITY_MAP: Record<string, string> = {
14	  listings: 'Listing',
15	  users: 'User',
16	  conversations: 'Conversation',
17	  settlements: 'Settlement',
18	};
19	
20	const ALLOWED_FIELDS: Record<string, string[]> = {
21	  listings: ['id', 'title', 'breed', 'region', 'priceUsd', 'age', 'rating', 'status', 'createdAt', 'vendorId'],
22	  users: ['id', 'username', 'role', 'isActive', 'createdAt'],
23	  conversations: ['id', 'listingId', 'vendorId', 'isArchived', 'isDisputed', 'createdAt'],
24	  settlements: ['id', 'vendorId', 'month', 'totalCharges', 'taxAmount', 'status', 'createdAt'],
25	};
26	
27	@Injectable()
28	export class QueryService {
29	  constructor(
30	    @InjectRepository(SavedQuery)
31	    private readonly savedQueryRepo: Repository<SavedQuery>,
32	    private readonly dataSource: DataSource,
33	    private readonly encryption: EncryptionService,
34	  ) {}
35	
36	  async execute(
37	    dto: PowerQueryDto,
38	    userId: string,
39	    role: string,
40	  ): Promise<{ items: unknown[]; total: number; page: number; limit: number; totalPages: number }> {
41	    const entityName = ENTITY_MAP[dto.entity];
42	    if (!entityName) throw new BadRequestException(`Unknown entity: ${dto.entity}`);
43	
44	    const allowed = ALLOWED_FIELDS[dto.entity] ?? [];
45	    const repo = this.dataSource.getRepository(entityName);
46	    const alias = 'e';
47	    const qb = repo.createQueryBuilder(alias);
48	
49	    if (role === 'vendor' && dto.entity === 'listings') {
50	      qb.andWhere(`${alias}.vendorId = :userId`, { userId });
51	    }
52	    if (role === 'vendor' && dto.entity === 'settlements') {
53	      qb.andWhere(`${alias}.vendorId = :userId`, { userId });
54	    }
55	
56	    if (dto.filters) {
57	      for (let i = 0; i < dto.filters.length; i++) {
58	        const f = dto.filters[i];
59	        if (!allowed.includes(f.field)) {
60	          throw new BadRequestException(`Field "${f.field}" not allowed for entity "${dto.entity}"`);
61	        }
62	        const paramName = `p${i}`;
63	        this.applyFilter(qb, alias, f, paramName);
64	      }
65	    }
66	
67	    if (dto.sort && allowed.includes(dto.sort.field)) {
68	      qb.orderBy(`${alias}.${dto.sort.field}`, dto.sort.dir.toUpperCase() as 'ASC' | 'DESC');
69	    } else {
70	      qb.orderBy(`${alias}.createdAt`, 'DESC');
71	    }
72	
73	    const page = Math.max(1, dto.page ?? 1);
74	    const limit = Math.min(100, Math.max(1, dto.limit ?? 20));
75	    qb.skip((page - 1) * limit).take(limit);
76	
77	    const [items, total] = await qb.getManyAndCount();
78	
79	    const masked = items.map((item: any) => {
80	      if (dto.entity === 'users' && role !== 'admin') {
81	        const { passwordHash, email, deviceFingerprint, ...safe } = item;
82	        return safe;
83	      }
84	      return item;
85	    });
86	
87	    return {
88	      items: masked,
89	      total,
90	      page,
91	      limit,
92	      totalPages: Math.ceil(total / limit),
93	    };
94	  }
95	
96	  async saveQuery(userId: string, name: string, params: Record<string, unknown>): Promise<SavedQuery> {
97	    const sq = this.savedQueryRepo.create({ userId, name, params });
98	    return this.savedQueryRepo.save(sq);
99	  }
100	
101	  async getSavedQueries(userId: string): Promise<SavedQuery[]> {
102	    return this.savedQueryRepo.find({
103	      where: { userId },
104	      order: { createdAt: 'DESC' },
105	    });
106	  }
107	
108	  async deleteSavedQuery(id: string, userId: string): Promise<void> {
109	    const sq = await this.savedQueryRepo.findOne({ where: { id } });
110	    if (!sq) throw new NotFoundException('Saved query not found');
111	    if (sq.userId !== userId) throw new ForbiddenException('Cannot delete another user\'s saved query');
112	    await this.savedQueryRepo.delete(id);
113	  }
114	
115	  private applyFilter(
116	    qb: SelectQueryBuilder<any>,
117	    alias: string,
118	    filter: QueryFilterItem,
119	    paramName: string,
120	  ): void {
121	    const col = `${alias}.${filter.field}`;
122	    switch (filter.op) {
123	      case 'eq':
124	        qb.andWhere(`${col} = :${paramName}`, { [paramName]: filter.value });
125	        break;
126	      case 'gt':
127	        qb.andWhere(`${col} > :${paramName}`, { [paramName]: filter.value });
128	        break;
129	      case 'lt':
130	        qb.andWhere(`${col} < :${paramName}`, { [paramName]: filter.value });
131	        break;
132	      case 'gte':
133	        qb.andWhere(`${col} >= :${paramName}`, { [paramName]: filter.value });
134	        break;
135	      case 'lte':
136	        qb.andWhere(`${col} <= :${paramName}`, { [paramName]: filter.value });
137	        break;
138	      case 'contains':
139	        qb.andWhere(`${col} ILIKE :${paramName}`, { [paramName]: `%${filter.value}%` });
140	        break;
141	      case 'in':
142	        if (Array.isArray(filter.value)) {
143	          qb.andWhere(`${col} IN (:...${paramName})`, { [paramName]: filter.value });
144	        }
145	        break;
146	    }
147	  }
148	}
