2	
3	export interface AuthUser {
4	  id: string;
5	  username: string;
6	  email: string;
7	  role: string;
8	}
9	
10	interface AuthState {
11	  user: AuthUser | null;
12	  token: string | null;
13	  role: string | null;
14	  login: (user: AuthUser, token: string) => void;
15	  logout: () => void;
16	}
17	
18	const SESSION_KEY = 'pm_auth';
19	
20	function loadFromSession(): { user: AuthUser | null; token: string | null } {
21	  try {
22	    const raw = sessionStorage.getItem(SESSION_KEY);
23	    if (!raw) return { user: null, token: null };
24	    return JSON.parse(raw) as { user: AuthUser; token: string };
25	  } catch {
26	    return { user: null, token: null };
27	  }
28	}
29	
30	const initial = loadFromSession();
31	
32	export const useAuthStore = create<AuthState>((set) => ({
33	  user: initial.user,
34	  token: initial.token,
35	  role: initial.user?.role ?? null,
36	
37	  login: (user: AuthUser, token: string) => {
38	    sessionStorage.setItem(SESSION_KEY, JSON.stringify({ user, token }));
39	    set({ user, token, role: user.role });
40	  },
41	
42	  logout: () => {
43	    sessionStorage.removeItem(SESSION_KEY);
44	    set({ user: null, token: null, role: null });
45	  },
46	}));
